mapper.select:
select ci.id, ci.holder_name, ci.card_type, ci.person_code, ci.decimal_code, ci.epc_code, ci.issue_time, ci.card_status, ci.create_by, ci.create_time, ci.update_by, ci.update_time, ci.remark, ci.user_id, su.user_number from card_issue ci left join sys_user su on ci.person_code = su.user_name and su.del_flag = '0'
AND ci.holder_name like concat('%', #{holderName}, '%')
AND ci.card_status = #{cardStatus}
AND ci.card_type = #{cardType}
AND ci.person_code = #{personCode}
AND ci.epc_code like concat('%', #{epcCode}, '%')
order by ci.id desc

mapper.update:
update card_issue
holder_name = #{holderName}, person_code = #{personCode}, card_type = #{cardType}, decimal_code = #{decimalCode}, epc_code = #{epcCode}, issue_time = #{issueTime}, card_status = #{cardStatus}, update_by = #{updateBy}, remark = #{remark}, user_id = #{userId}, update_time = sysdate()
where id = #{id}

mapper.select:
select count(1) from card_issue
where person_code = #{personCode}
and card_type = #{cardType}
and card_status = #{type}

	and id != #{excludeId}

select count(1) from card_issue
where person_code = #{personCode}
and card_type = #{cardType}
